async (page) => {
  var title = "图解 Blaze · 第 5 章 · 高级 Entity View — 图解 Blaze-Persistence";
  var html = "<section style=\"margin-bottom:24px;\">\n<h2 style=\"font-size:24px;font-weight:800;color:#1a1a2e;line-height:1.4;margin:0 0 8px;\">第 5 章 · 高级 Entity View</h2>\n</section>\n<section><p style=\"font-size:14px;color:#888;margin-bottom:28px;line-height:1.7;\">子视图 · 继承映射 · 集合映射 · @MappingCorrelated · Flat View</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px 14px;margin:0 0 28px;line-height:1.9;\"><p style=\"font-size:15px;color:#2b2b2b;margin-bottom:10px;line-height:1.8;\">\n    第 4 章掌握了 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EntityView</code> 的基础映射后，本章深入探索高级投影能力：\n    <strong style=\"color:#1a1a2e;font-weight:700;\">子视图嵌套</strong>实现对象树投影、<strong style=\"color:#1a1a2e;font-weight:700;\">继承映射</strong>处理多态实体、\n    <strong style=\"color:#1a1a2e;font-weight:700;\">集合映射</strong>的三种抓取策略、<strong style=\"color:#1a1a2e;font-weight:700;\">关联子查询</strong>构建派生字段、\n    以及 <strong style=\"color:#1a1a2e;font-weight:700;\">Flat View</strong> 将嵌套结构拍平到一层。\n  </p><ul style=\"margin:8px 0 8px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:4px;font-size:13px;\">用 Subview 构建嵌套对象图并自动优化为单条 SQL</li><li style=\"margin-bottom:4px;font-size:13px;\">通过继承映射投影多态 JPA 实体</li><li style=\"margin-bottom:4px;font-size:13px;\">掌握 JOIN / SUBSELECT / MULTISET 三种集合抓取策略</li><li style=\"margin-bottom:4px;font-size:13px;\">使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@MappingCorrelated</code> 嵌入关联子查询</li><li style=\"margin-bottom:4px;font-size:13px;\">Flat View 扁平化投影与常规子视图的取舍</li><li style=\"margin-bottom:4px;font-size:13px;\">用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@MappingParameter</code> 向视图注入运行时参数</li><li style=\"margin-bottom:4px;font-size:13px;\">识别深层嵌套、集合分页冲突等常见陷阱</li></ul><p style=\"font-size:12px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">前置：<span style=\"color:#1e6fff;\">第 4 章 · Entity View 基础</span></p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">5.1 子视图嵌套（Subview）</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">当 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Mapping</code> 方法的返回类型本身也是一个 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EntityView</code> 时，Blaze-Persistence 自动将其识别为<strong style=\"color:#1a1a2e;font-weight:700;\">子视图（Subview）</strong>。这是构建复杂 DTO 对象树的基础。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">子视图嵌套解析：OrderView → OrderItemView → ProductView</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Order</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">class</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">OrderItem</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Product</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">OrderView<br/>@EntityView(Order.class)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">OrderItemView<br/>@EntityView(OrderItem.class)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ProductView<br/>@EntityView(Product.class)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">id · status · totalPrice</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">quantity · unitPrice</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">name · sku</p></section></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">三个 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EntityView</code> 接口形成嵌套链。框架在<strong style=\"color:#1a1a2e;font-weight:700;\">编译期（EntityViewManager 初始化）</strong>就完成了嵌套解析，运行时直接生成优化后的单条查询。</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Product.class)<br/>public interface ProductView {<br/>    @IdMapping<br/>    Long getId();<br/>    String getName();<br/>    String getSku();<br/>}<br/><br/>@EntityView(OrderItem.class)<br/>public interface OrderItemView {<br/>    @IdMapping<br/>    Long getId();<br/>    Integer getQuantity();<br/>    BigDecimal getUnitPrice();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 返回类型是另一个 EntityView → 自动子视图</span><br/>    ProductView getProduct();<br/>}<br/><br/>@EntityView(Order.class)<br/>public interface OrderView {<br/>    @IdMapping<br/>    Long getId();<br/>    String getStatus();<br/>    BigDecimal getTotalPrice();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// List&lt;子视图&gt; → 自动嵌套集合投影</span><br/>    List&lt;OrderItemView&gt; getItems();<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Blaze-Persistence 将嵌套视图合并为单条优化 SQL</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">视图定义</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">OrderView</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">OrderItemView</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">ProductView</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">EntityViewManager</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">解析 @Mapping 树</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">合并 SELECT 列</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">生成 JOIN 子句</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">生成 SQL</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">SELECT o.id, o.status,<br/>oi.quantity, oi.unitPrice,<br/>p.name, p.sku<br/>FROM Order o<br/>JOIN o.items oi<br/>JOIN oi.product p</p></section></td></tr></table></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 关键优势：</strong>无论嵌套多少层，Blaze-Persistence 仅生成<strong style=\"color:#1a1a2e;font-weight:700;\">一条 SQL</strong>（默认 JOIN 策略）。\n  SELECT 子句只包含视图中实际声明的字段，避免 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SELECT *</code> 带来的多余列传输。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">5.2 继承映射（Inheritance）</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">JPA 实体可以有继承层次（<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SINGLE_TABLE</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JOINED</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">TABLE_PER_CLASS</code>）。Blaze-Persistence Entity View 同样支持<strong style=\"color:#1a1a2e;font-weight:700;\">多态投影</strong>：定义基础视图接口，派生子视图映射到不同实体子类。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Entity View 继承层次：AnimalView → CatView / DogView</p><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">AnimalView</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;@EntityView · Long getId · String getName · Double getWeight</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">CatView</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;@EntityView · Boolean isIndoor · String getBreed</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">DogView</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;@EntityView · String getBarkVolume · Boolean isTrained</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">Animal</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;JPA Entity&gt;&gt; · Long id · String name · Double weight · String dtype</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">Cat</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;JPA Entity&gt;&gt; · Boolean indoor · String breed</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">Dog</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;JPA Entity&gt;&gt; · String barkVolume · Boolean trained</p></section></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Animal.class)<br/>@EntityViewInheritance<br/>public interface AnimalView {<br/>    @IdMapping<br/>    Long getId();<br/>    String getName();<br/>    Double getWeight();<br/>}<br/><br/>@EntityView(Cat.class)<br/>@EntityViewInheritanceMapping(\"TYPE(this) = Cat\")<br/>public interface CatView extends AnimalView {<br/>    Boolean isIndoor();<br/>    String getBreed();<br/>}<br/><br/>@EntityView(Dog.class)<br/>@EntityViewInheritanceMapping(\"TYPE(this) = Dog\")<br/>public interface DogView extends AnimalView {<br/>    String getBarkVolume();<br/>    Boolean isTrained();<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">多态视图解析流程</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">查询 AnimalView\"] --> EVM[\"EntityViewManager<br/>检查 @EntityViewInheritance</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityViewManager<br/>检查 @EntityViewInheritance</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 判别器<br/>TYPE(this)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">实例化 CatView<br/>填充 indoor, breed</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">实例化 DogView<br/>填充 barkVolume, trained</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">实例化 AnimalView<br/>仅基础字段</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">List<AnimalView><br/>包含混合类型</p></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #e6a81744;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">⚠️ 注意：</strong><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EntityViewInheritanceMapping</code> 的表达式使用 JPQL 语法。\n  <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">TYPE(this)</code> 对应 JPA 的类型判别函数，它会被翻译为数据库中的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">DTYPE</code> 列比较。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">5.3 集合映射</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Entity View 可以映射 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">List</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Set</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Map</code> 类型的关联集合。关键在于选择正确的<strong style=\"color:#1a1a2e;font-weight:700;\">抓取策略</strong>——不同策略产生截然不同的 SQL 形态和性能特征。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">三种集合抓取策略对比</p><section style=\"margin:3px 0;padding:8px 12px;background:rgb(210,153,34);border-left:3px solid #d29922;border-radius:4px;\"><p style=\"margin:0;font-size:12px;line-height:1.6;\"><span style=\"color:#d29922;\">JOIN 策略</span> <span style=\"color:#e6edf3;\">单条 SQLLEFT JOIN 集合表⚠️ 主实体行重复适合小集合</span></p></section><section style=\"margin:3px 0;padding:8px 12px;background:rgb(88,166,255);border-left:3px solid #58a6ff;border-radius:4px;\"><p style=\"margin:0;font-size:12px;line-height:1.6;\"><span style=\"color:#58a6ff;\">SUBSELECT 策略</span> <span style=\"color:#e6edf3;\">两条 SQL主查询 + 子查询✅ 无行重复适合中等集合</span></p></section><section style=\"margin:3px 0;padding:8px 12px;background:rgb(63,185,80);border-left:3px solid #3fb950;border-radius:4px;\"><p style=\"margin:0;font-size:12px;line-height:1.6;\"><span style=\"color:#3fb950;\">⭐ MULTISET 策略</span> <span style=\"color:#e6edf3;\">单条 SQL嵌套集合作为子列✅ 无行重复推荐策略</span></p></section></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">策略</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">SQL 条数</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">行重复</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">嵌套支持</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">适用场景</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">FetchStrategy.JOIN</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">1</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">是（笛卡尔积风险）</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">多层 JOIN 可能爆炸</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">小集合、单层嵌套</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">FetchStrategy.SUBSELECT</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">N+1（但可批量）</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">否</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">良好</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">中等集合、需要分页</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">FetchStrategy.MULTISET</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">1</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">否</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">优秀</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">复杂嵌套、大集合 ⭐</td></tr></table></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Order.class)<br/>public interface OrderWithItemsView {<br/>    @IdMapping<br/>    Long getId();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 默认 JOIN 策略</span><br/>    List&lt;OrderItemView&gt; getItems();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 显式指定 MULTISET 策略（推荐）</span><br/>    @Mapping(fetch = FetchStrategy.MULTISET)<br/>    List&lt;OrderItemView&gt; getItemsMultiset();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// SUBSELECT 策略</span><br/>    @Mapping(fetch = FetchStrategy.SUBSELECT)<br/>    Set&lt;TagView&gt; getTags();<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">抓取策略对生成 SQL 的影响</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">应用代码</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityViewManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 JOIN 策略</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 MULTISET 策略</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 最佳实践：</strong>优先使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">MULTISET</code> 策略。它在单条 SQL 中内嵌子集合，避免笛卡尔积，\n  是 Blaze-Persistence 相比原生 JPA 的核心差异化特性之一。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">5.4 @MappingCorrelated 关联子查询</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">有些派生字段无法通过简单的路径映射表达——例如统计关联实体数量、计算聚合值、或引用不相关的实体。<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@MappingCorrelated</code> 允许在视图中嵌入<strong style=\"color:#1a1a2e;font-weight:700;\">关联子查询</strong>。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">@MappingCorrelated 执行时序</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityView 定义</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityViewManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">CorrelationProvider</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">SQL 引擎</th></tr></table></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CorrelationProvider</code> 是关联子查询的核心接口。它接收一个 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilder</code>，返回一个与主查询关联的子查询片段。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">CorrelationProvider 接口与数据流</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">CorrelationProvider</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">provideCorrelation(<br/>CorrelationBuilder cb)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">cb.correlate(Entity.class)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">.where('field')<br/>.eqExpression(<br/>'EMBEDDING_VIEW(id)')</p></section></td></tr></table></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">生成 SQL</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">SELECT COUNT(*)<br/>FROM orders o2<br/>WHERE o2.customer_id<br/>= c.id</p></section></td></tr></table></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 1. 定义 CorrelationProvider</span><br/>public class OrderCountProvider implements CorrelationProvider {<br/>    @Override<br/>    public void applyCorrelation(<br/>            CorrelationBuilder correlationBuilder,<br/>            String correlationExpression) {<br/>        correlationBuilder<br/>            .correlate(Order.class)<br/>            .on(\"customer.id\")<br/>            .eqExpression(correlationExpression)<br/>            .end();<br/>    }<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 2. 在 EntityView 中使用关联子查询</span><br/>@EntityView(Customer.class)<br/>public interface CustomerSummaryView {<br/>    @IdMapping<br/>    Long getId();<br/>    String getName();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 关联子查询：统计该客户的订单数</span><br/>    @MappingCorrelated(<br/>        correlationBasis = \"id\",<br/>        correlator = OrderCountProvider.class,<br/>        correlationResult = \"id\",<br/>        fetch = FetchStrategy.JOIN<br/>    )<br/>    Long getOrderCount();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 关联子查询：计算总消费金额</span><br/>    @MappingCorrelated(<br/>        correlationBasis = \"id\",<br/>        correlator = TotalSpentProvider.class,<br/>        correlationResult = \"totalPrice\",<br/>        fetch = FetchStrategy.JOIN<br/>    )<br/>    BigDecimal getTotalSpent();<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#e05252;margin-bottom:8px;\">❌ 错误示范</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 原生方式：先查客户，再循环查订单数</span><br/>List&lt;Customer&gt; customers = em<br/>    .createQuery(\"FROM Customer\")<br/>    .getResultList();<br/>for (Customer c : customers) {<br/>    Long count = em.createQuery(<br/>        \"SELECT COUNT(o) FROM Order o \" +<br/>        \"WHERE o.customer = :c\", Long.class)<br/>        .setParameter(\"c\", c)<br/>        .getSingleResult();<br/>    <span style=\"color:#6c7086;font-style:italic;\">// N+1 查询！</span><br/>}</p></section><section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#1e6fff;margin-bottom:8px;\">✅ 正确做法</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// @MappingCorrelated 方式</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 生成单条 SQL：</span><br/><span style=\"color:#6c7086;font-style:italic;\">// SELECT c.id, c.name,</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   (SELECT COUNT(*)</span><br/><span style=\"color:#6c7086;font-style:italic;\">//    FROM orders o</span><br/><span style=\"color:#6c7086;font-style:italic;\">//    WHERE o.customer_id = c.id)</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   AS orderCount</span><br/><span style=\"color:#6c7086;font-style:italic;\">// FROM customers c</span><br/><br/>List&lt;CustomerSummaryView&gt; result =<br/>    evm.applySetting(<br/>        EntityViewSetting.create(<br/>            CustomerSummaryView.class),<br/>        cb)<br/>    .getResultList();</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e6a81744;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">⚠️ 何时使用关联 vs 常规映射：</strong>\n  如果目标属性可以通过 JPA 关联路径（如 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">order.customer.name</code>）到达，使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Mapping</code> 即可。\n  只有当需要<strong style=\"color:#1a1a2e;font-weight:700;\">聚合计算</strong>、<strong style=\"color:#1a1a2e;font-weight:700;\">跨无关联实体</strong>或<strong style=\"color:#1a1a2e;font-weight:700;\">复杂过滤</strong>时才需要 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@MappingCorrelated</code>。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">5.5 Flat View</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">常规子视图会生成嵌套对象结构（如 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">orderView.getAddress().getCity()</code>），而 <strong style=\"color:#1a1a2e;font-weight:700;\">Flat View</strong> 将关联实体的字段直接<strong style=\"color:#1a1a2e;font-weight:700;\">扁平化</strong>到父视图层级，省去中间层。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">嵌套子视图 vs Flat View 的结构对比</p><section style=\"margin:3px 0;padding:8px 12px;background:rgb(210,153,34);border-left:3px solid #d29922;border-radius:4px;\"><p style=\"margin:0;font-size:12px;line-height:1.6;\"><span style=\"color:#d29922;\">常规子视图（嵌套结构）</span> <span style=\"color:#e6edf3;\">OrderView↳getAddress()→ AddressView↳ getStreet()↳ getCity()↳ getZipCode()</span></p></section><section style=\"margin:3px 0;padding:8px 12px;background:rgb(63,185,80);border-left:3px solid #3fb950;border-radius:4px;\"><p style=\"margin:0;font-size:12px;line-height:1.6;\"><span style=\"color:#3fb950;\">Flat View（扁平结构）</span> <span style=\"color:#e6edf3;\">OrderView↳ getAddressStreet()↳ getAddressCity()↳ getAddressZipCode()</span></p></section></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@MappingFlat</code> 或直接在 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Mapping</code> 中指定路径表达式即可将关联属性拍平：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Order.class)<br/>public interface OrderFlatView {<br/>    @IdMapping<br/>    Long getId();<br/>    String getStatus();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 扁平化：直接映射关联实体 Address 的字段</span><br/>    @Mapping(\"shippingAddress.street\")<br/>    String getShippingStreet();<br/><br/>    @Mapping(\"shippingAddress.city\")<br/>    String getShippingCity();<br/><br/>    @Mapping(\"shippingAddress.zipCode\")<br/>    String getShippingZipCode();<br/><br/>    @Mapping(\"shippingAddress.country.name\")<br/>    String getShippingCountryName();<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Flat View 的 SQL 投影——JOIN 但不创建中间对象</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">生成 SQL</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">SELECT o.id, o.status,<br/>a.street, a.city,<br/>a.zip_code, c.name<br/>FROM orders o<br/>JOIN addresses a ON ...<br/>JOIN countries c ON ...</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">返回结果</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">OrderFlatView {<br/>  id: 1001<br/>  status: 'SHIPPED'<br/>  shippingStreet: '中关村大街1号'<br/>  shippingCity: '北京'<br/>  shippingZipCode: '100080'<br/>  shippingCountryName: '中国'<br/>}</p></section></td></tr></table></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#e05252;margin-bottom:8px;\">❌ 错误示范</p><p style=\"font-size:13px;color:#2b2b2b;margin-bottom:6px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">子视图嵌套：</strong>生成中间 AddressView 对象，需额外内存。JSON 序列化后为嵌套 JSON：</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">{<br/>  \"id\": 1001,<br/>  \"address\": {<br/>    \"street\": \"中关村大街1号\",<br/>    \"city\": \"北京\"<br/>  }<br/>}</p></section><section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#1e6fff;margin-bottom:8px;\">✅ 正确做法</p><p style=\"font-size:13px;color:#2b2b2b;margin-bottom:6px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Flat View：</strong>无中间对象，字段直接平铺。适合表格展示、CSV 导出：</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">{<br/>  \"id\": 1001,<br/>  \"shippingStreet\": \"中关村大街1号\",<br/>  \"shippingCity\": \"北京\"<br/>}</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">5.6 @MappingParameter 与上下文参数</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">某些映射需要运行时上下文——例如当前用户的 Locale 决定名称字段读取哪一列。<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@MappingParameter</code> 允许在 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewSetting</code> 中传入参数，视图定义中引用。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">参数从 Setting 流向 View 的完整路径</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">setting</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">withOptionalParameter</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">EntityViewManager<br/>.applySetting()</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">applySetting</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">p</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">name_zh</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">应用代码<br/>setting.withOptionalParameter(<br/>'locale', Locale.CHINESE)\"] --> B[\"EntityViewSetting<br/>参数池</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">EntityViewSetting<br/>参数池</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">视图实例化<br/>@MappingParameter('locale')<br/>Locale locale</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">CASE 表达式<br/>@Mapping(CASE WHEN :locale = 'zh'<br/>THEN nameZh ELSE nameEn)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">SQL 生成<br/>CASE WHEN ? = 'zh'<br/>THEN p.name_zh<br/>ELSE p.name_en END</p></section></td></tr></table></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Product.class)<br/>public interface LocalizedProductView {<br/>    @IdMapping<br/>    Long getId();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 根据运行时 locale 参数选择名称列</span><br/>    @Mapping(\"CASE WHEN :locale = 'zh' THEN nameZh ELSE nameEn END\")<br/>    String getDisplayName();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 注入参数本身</span><br/>    @MappingParameter(\"locale\")<br/>    String getLocale();<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 调用方设置参数</span><br/>EntityViewSetting&lt;LocalizedProductView, CriteriaBuilder&lt;LocalizedProductView&gt;&gt; setting =<br/>    EntityViewSetting.create(LocalizedProductView.class);<br/>setting.withOptionalParameter(\"locale\", \"zh\");<br/><br/>List&lt;LocalizedProductView&gt; products =<br/>    evm.applySetting(setting, cb).getResultList();</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 参数类型：</strong><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">withOptionalParameter</code> 允许视图在未传参时使用默认值；\n  <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">withParameter</code> 则为必需参数——缺失时抛出异常。参数可以是任意 Java 对象，不限于基本类型。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">5.7 陷阱与限制</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">高级 Entity View 功能强大但有边界。以下是实践中最常见的陷阱：</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">高级 Entity View 常见陷阱全景</p><section style=\"margin:3px 0;padding:8px 12px;background:rgb(248,81,73);border-left:3px solid #f85149;border-radius:4px;\"><p style=\"margin:0;font-size:12px;line-height:1.6;\"><span style=\"color:#f85149;\">🔴 深层嵌套</span> <span style=\"color:#8b949e;\">3+ 层子视图 → 多重 JOIN、笛卡尔积风险</span> <span style=\"color:#3fb950;\">✅ 解法：MULTISET</span></p></section><section style=\"margin:3px 0;padding:8px 12px;background:rgb(248,81,73);border-left:3px solid #f85149;border-radius:4px;\"><p style=\"margin:0;font-size:12px;line-height:1.6;\"><span style=\"color:#f85149;\">🔴 集合 + 分页</span> <span style=\"color:#8b949e;\">集合 JOIN → 行重复导致分页数量不准</span> <span style=\"color:#3fb950;\">✅ 解法：SUBSELECT 或 MULTISET</span></p></section><section style=\"margin:3px 0;padding:8px 12px;background:rgb(248,81,73);border-left:3px solid #f85149;border-radius:4px;\"><p style=\"margin:0;font-size:12px;line-height:1.6;\"><span style=\"color:#f85149;\">🔴 继承层数</span> <span style=\"color:#8b949e;\">多层继承 → 判别逻辑复杂、SELECT 列爆炸</span> <span style=\"color:#3fb950;\">✅ 解法：限制 2 层，用组合替代</span></p></section><section style=\"margin:3px 0;padding:8px 12px;background:rgb(248,81,73);border-left:3px solid #f85149;border-radius:4px;\"><p style=\"margin:0;font-size:12px;line-height:1.6;\"><span style=\"color:#f85149;\">🔴 Correlated N+1</span> <span style=\"color:#8b949e;\">@MappingCorrelated + JOIN → 默认单行执行</span> <span style=\"color:#3fb950;\">✅ 解法：设置 batchSize 或 SUBSELECT</span></p></section><section style=\"margin:3px 0;padding:8px 12px;background:rgb(248,81,73);border-left:3px solid #f85149;border-radius:4px;\"><p style=\"margin:0;font-size:12px;line-height:1.6;\"><span style=\"color:#f85149;\">🔴 Flat + Optional</span> <span style=\"color:#8b949e;\">Flat View 映射可选关联 → NULL 时全部字段为空</span> <span style=\"color:#3fb950;\">✅ 解法：子视图整体可空更清晰</span></p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">5.7.1 深层嵌套与笛卡尔积</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">当子视图嵌套超过 3 层、且多层都包含集合映射时，默认 JOIN 策略会产生笛卡尔积——查询结果行数 = 各层集合大小之积。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">🚨 危险模式：</strong>Order(10行) → Items(5/单) → Tags(3/单) = <strong style=\"color:#1a1a2e;font-weight:700;\">150 行</strong>结果。\n  切换为 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">MULTISET</code> 后回到 <strong style=\"color:#1a1a2e;font-weight:700;\">10 行</strong>。\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">5.7.2 集合映射与分页冲突</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">使用 JOIN 抓取集合时，<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">LIMIT / OFFSET</code> 作用于 JOIN 后的行而非实体。10 个 Order 各含 5 个 Item，<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">LIMIT 10</code> 只返回 2 个 Order 的数据。</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ 错误：集合 JOIN + 分页导致数据截断</span><br/>CriteriaBuilder&lt;OrderView&gt; cb = cbf.create(em, OrderView.class)<br/>    .orderByAsc(\"id\")<br/>    .page(0, 10); <span style=\"color:#6c7086;font-style:italic;\">// LIMIT 10 作用于 JOIN 后的行！</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ✅ 正确：集合使用 MULTISET，分页作用于主实体</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 或将集合改为 SUBSELECT 策略</span></p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">5.7.3 @MappingCorrelated 的 N+1 风险</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">默认情况下关联子查询随主查询一起内联。但如果配合 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SUBSELECT</code> fetch 且未设置 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">batchSize</code>，每行会触发一次独立的关联查询。</p></section>\n\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">5.7.4 Flat View 与可选关联</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">当被 Flat 映射的关联是 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@ManyToOne(optional = true)</code> 时，关联为 NULL 意味着所有扁平字段都是 NULL——无法区分\"关联存在但字段为空\"和\"关联本身不存在\"。此时使用可空的子视图更加语义明确。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:8px;padding:14px 16px;margin:14px 0 20px;\"><p style=\"font-size:11px;font-weight:700;color:#1e6fff;letter-spacing:.5px;margin-bottom:8px;\">🔍 实战案例</p><p style=\"font-size:14px;font-weight:600;color:#1e6fff;margin:0 0 6px;\">实战经验</p><p style=\"font-size:13px;color:#2b2b2b;margin-bottom:6px;line-height:1.7;\">在电商系统中，订单的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">billingAddress</code> 可能为空（使用发货地址结算）。\n  如果对 billingAddress 使用 Flat View，当地址不存在时，<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">billingStreet</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">billingCity</code> 全部为 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">null</code>，\n  客户端无法区分是\"没有独立结算地址\"还是\"地址信息未填\"。</p><p style=\"font-size:13px;color:#2b2b2b;margin-bottom:6px;line-height:1.7;\">推荐方案：使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Mapping(\"billingAddress\") AddressView getBillingAddress()</code>，关联不存在时整个子视图返回 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">null</code>。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px;margin:36px 0 16px;\"><p style=\"font-size:18px;font-weight:700;color:#1e6fff;margin:0 0 12px;\">📋 📋 本章小结</p><ul style=\"margin:8px 0 12px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">子视图嵌套</strong>：返回类型为 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EntityView</code> 时自动识别为子视图，合并为单条优化 SQL</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">继承映射</strong>：<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EntityViewInheritance</code> + <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EntityViewInheritanceMapping</code> 实现多态 DTO 投影</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">集合策略</strong>：JOIN（小集合）、SUBSELECT（需分页）、MULTISET（推荐，无笛卡尔积）</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">关联子查询</strong>：<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@MappingCorrelated</code> + <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CorrelationProvider</code> 嵌入聚合计算，优于手动 N+1 循环</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Flat View</strong>：路径表达式扁平化嵌套结构，适合表格/CSV 场景，注意可选关联的语义陷阱</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">@MappingParameter</strong>：运行时参数注入，实现 Locale 切换等动态逻辑</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">陷阱警示</strong>：深层嵌套用 MULTISET、集合分页避免 JOIN、关联子查询注意批处理</li></ul><p style=\"font-size:13px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">\n    下一章 <span style=\"color:#1e6fff;\">第 6 章 · 可更新与可创建视图</span> 将介绍如何通过\n    <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@UpdatableEntityView</code> 和 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@CreatableEntityView</code> 实现基于 DTO 的写操作，\n    包括脏检查、级联策略与乐观锁机制。\n  </p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">© 2026 图解 Blaze-Persistence · 第 5 章 · 由 AI 辅助生成</p></section>";
  await page.waitForSelector('.ProseMirror', { timeout: 15000 });
  if (title) {
    var ti = page.locator('textarea[placeholder="请在这里输入标题"]');
    await ti.fill(title);
    await page.waitForTimeout(300);
  }
  await page.evaluate((h) => {
    var pm = document.querySelector('.ProseMirror');
    pm.focus();
    var dt = new DataTransfer();
    dt.setData('text/html', h);
    var ev = new ClipboardEvent('paste', {bubbles:true, cancelable:true, clipboardData:dt});
    pm.dispatchEvent(ev);
  }, html);
  await page.waitForTimeout(1500);
  var enableBtns = page.locator('label:has-text("开启")');
  var cnt = await enableBtns.count();
  for (var i = 0; i < cnt; i++) {
    try {
      var b = enableBtns.nth(i);
      if (await b.isVisible({ timeout: 500 })) await b.click({ timeout: 1000 });
    } catch(e) {}
  }
  await page.waitForTimeout(500);
  var saveBtn = page.getByRole('button', { name: '保存为草稿' });
  await saveBtn.click();
  await page.waitForTimeout(2000);
  return title + ' -> saved';
}